Infraestrutura como codigo para devops - TechCorp Brasil - ecommerce-migration:

**main.tf:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region = "sa-saopaulo-1"
}

resource "oci_devops_project" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "devops-production-000"

  # Configuracao especifica
  shape          = "VM.Standard.E4.Flex"

  tags = {
    project     = "TechCorp Brasil - ecommerce-migration"
    environment = "production"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment production"
}

output "resource_id" {
  value = oci_devops_project.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "sa-saopaulo-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=<ocid>"
terraform apply -var="compartment_ocid=<ocid>" -auto-approve
```

**Configuracao:**
- Compartment: `production`
- Region: `sa-saopaulo-1`
- Shape: `VM.Standard.E4.Flex`
- OCPUs: `1`
- Storage: `50 GB`

Documentacao: https://registry.terraform.io/providers/oracle/oci/latest/docs

